Table Purpose <code>saga_events</code> Event Store - all SAGA events (append-only) <code>saga_snapshots</code> Periodic snapshots to optimize replay <pre><code>CREATE TABLE saga_events (
    id BIGSERIAL PRIMARY KEY,
    booking_id UUID NOT NULL,
    event_type VARCHAR(100) NOT NULL,
    event_data JSONB NOT NULL,
    correlation_id UUID NOT NULL,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    sequence_number INT NOT NULL
);

CREATE INDEX idx_saga_events_booking_id ON saga_events(booking_id);
CREATE UNIQUE INDEX idx_saga_events_booking_sequence
    ON saga_events(booking_id, sequence_number);
</code></pre>
